import{_ as e,o as a,c as b,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"下落恶魔","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/2.社交类/下落恶魔.md","filePath":"4.资源分区/2.改造与功法/改造/2.社交类/下落恶魔.md"}'),s={name:"4.资源分区/2.改造与功法/改造/2.社交类/下落恶魔.md"};function d(o,p,l,_,i,c){return a(),b("div",null,[...p[0]||(p[0]=[r("h1",{id:"下落恶魔",tabindex:"-1"},[t("下落恶魔 "),r("a",{class:"header-anchor",href:"#下落恶魔","aria-label":'Permalink to "下落恶魔"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),n('<h1 id="下落恶魔-1" tabindex="-1">下落恶魔 <a class="header-anchor" href="#下落恶魔-1" aria-label="Permalink to &quot;下落恶魔&quot;">​</a></h1><p>下落恶魔<br> 特异本质<br> 改造<br> 描述：根源性恐惧，即所有生物的内心深处最基本的恐惧，无法改变的恐惧，未知来源的声响、无法感知的黑暗、无力反抗的下落……所谓恶魔，即从恐惧中来，生物愈加对其恐惧，恶魔的力量便愈加强大；而从根源性恐惧诞生之物——根源性恶魔，便是在恶魔之中，亦是未尝死亡的强大。</p><p>特殊的，从购买D级开始，购买者的心理和肉体已经不能被称之为【人类】了，这也代表任何人类的道德观念和价值观对于购买者都会变得陌生且不知有何意义，购买者需要在扮演中体现出这这一点，即对生命与道德的漠视。</p><p>【敕罪】：购买该改造时，你需要从【操控-社交-专业：哄骗-辅助专业：心理学】和【风度-社交-专业：威吓-辅助专业：心理学】中选择一个，以所选的属性-技能-专业作为该下落恶魔独有的施法攻击检定，一经选择无法更改。</p><p>购买该改造后将开启对应等级的下属技能（若有）购买权。</p><p>D级：优雅的魔人<br> D+600<br> 描述：摒弃凡俗，从容，优雅，往日之影在耳畔回荡，随着风声摇晃，嘭、嘭……鲜血如莲华绽放；结果到来前的那一丝悔意，主菜最精美的调料。<br> 特性：【将以此心】【献以坠落】【蔓延恐惧】<br> 【将以此心】：心脏处的空虚，那是人之心不存的佐证。你因此承受不可减免且永久存在不可消除的1点沮丧点数，同时，你的生物类型将转变为【黑暗生物】，这会让你的虹膜颜色转变为无高光的暗金色并出现白色套嵌圆形图案。<br> 同时，你获得名为【敕罪】的施法攻击方式，基础射程为15米，仅需轻轻挑动手指，就可轻而易举地挑动人内心的痛苦，你这次攻击在表现上为黑色的射线，将造成负能量伤害。</p><p>【献以坠落】：举手投足间，万物随之倾倒。现在你的施法攻击在投掷攻击出目后，可以选择令这次攻击不造成伤害，转为造成D级时空来源的击飞效果，目标针对这次攻击出目进行意志豁免，豁免失败目标立即向着当前重力的相反方向坠落豁免差值*米（以地球为例，即原地向上如高空自由落体般反重力起飞），并在击飞的同时感受到重力的反斥，因压力降低行动能力，这是一个D级诅咒来源的困难地形效果。</p><p>【蔓延恐惧】：行于高处，自上而下去俯瞰，无论何人，恐惧都会在心底蔓延，因为，你就在眼前。现在，每当你经历过一场影片，你就获得1点内在法术强度，这视为一个诅咒来源的内在加值，象征着你自身在非人之途愈走愈远。</p><p>C级：恶魔的帮厨<br> C+1200<br> 描述：你的技艺跨过了一道门槛，足以为饥肠辘辘的食客们做好定制佳肴前的准备工序，以你的仁慈为刀，以下坠为早已郁结的人们送去期待已久的解放。<br> 【无底坠落】：现在，你以【敕罪】进行的施法攻击可以应用的击飞效果提升为C级，如常以意志豁免对抗出目，若因这次攻击被击飞，则受到攻击者立即反重力坠落豁免后的差值米数，若不足60，则至少会提升至反重力坠落60米。<br> 从该等级开始，以【敕罪】进行法术攻击将额外提升等同于风度*1米的施法射程。<br> 你以【敕罪】进行的法术攻击总是额外附带有等量的【自责感】点数，这是一种类疲乏的一档情绪异常点数，以意志豁免。<br> 除此之外，被你击飞的目标将再下降一级飞行等级（完美-良好-通常-笨拙-无）最低至无，这是一个C级时空来源的负面效果，持续到其坠落为止。</p><p>自责感-无力感<br> 自责感是一种类疲乏的一档情绪异常点数，但其效果来源为影响心灵来源，这是人物的心灵承受错误引导产生的过度压抑感，因此产生的躯体化影响便是无力感。</p><p>B级：地狱的主厨<br> B+2400<br> 描述：长久的磨练，正如一把好刀须得经过多道打磨工序那般，你终于能够独当一面，握住属于你自己的主厨刀了；回头看，垂涎已久的食客们等待着，它们的目光挤出地狱的门扉，等待着你的旷世巨作。<br> 【汤品与前菜】：现在，以【敕罪】进行的施法攻击若为线型，则改为自身为中心，以该施法攻击射程为半径的圆形区域范围内的所有敌人进行一次攻击，只需在施法过程中轻轻抬手，就可以用法术攻击出目作为豁免dc，在保留这次法术攻击效果的同时，令所有承受攻击的单位反方向坠落，意志豁免对抗出目，这是一个B级时空来源的击飞效果，这些敌人将在C级的基础上由于强烈的压力再额外下降2级飞行等级（完美-良好-通常-笨拙-无）最低至无，直至其坠落为止。<br> 【主菜与甜品】：在D级的基础上，使所有因豁免失败而被击飞目标陷入更加恐怖的斥力之中，令其难以行动，这视为所有目标陷入C级诅咒来源的困难地形之中，持续一轮，被你击飞并受到坠落伤害的目标会在那一轮承受意志豁免上的【劣化1】。<br> 除此之外，你在地狱与现实直接锁定了自身的存在，这使得你免疫B级及以下的异空间效果。</p><p>A级：下落的恶魔<br> A+4800<br> 描述：放下染血的餐刀，朦胧的优雅礼仪之下，是无人能以从容面对的真正恐怖。<br> 【下落的恶魔】：现在，你已经达到了凡世能够忍受的极限，一举一动皆为醉人的真实。你在每个回合开始时获得仅用于进行【敕罪】施法攻击的8AP，同时，你的【敕罪】施法攻击范围将改为等同于你的敏感范围。<br> 达到等级，你以【敕罪】令他人反方向坠落的能力达到了一种艺术化的巅峰，那些进行意志豁免后没有高于你攻击出目者纷纷反重力坠落，就好像他们没有被击飞，而是他们追随着离地而去的重力飞向天空，这是一个A级环境来源的击飞效果。<br> 身为根源恶魔之一，死亡对你而言就如睡前的摇篮曲，而你永不会因简单的歌谣而合目，你获得了诅咒来源的免疫S级即死效果。</p><p>S级：根源的恐怖<br> S+9600<br> 描述：下落，于人类而言最无助的时刻，当耳旁的空气在摩擦中发出无助的嘶明，瞳孔中的大地张开双臂将使拥入怀抱，此生的记忆也将如梦幻泡影；然，作为人类其本能恐惧之存在，你自然有权利令人恐惧，令人安定，令人在下落中挣扎，令人在绝望中沉沦。<br> 针对下落的恐惧本质是人类对无法掌控自身的恐惧；而你熟练掌握着如此概念，字面意义上的，世界将围绕你旋转，只要你想，凡世便萦绕在你的指尖。<br> 【根源性恶魔】：下坠，上升，世事万物在你翻手之间颠覆；以你自身为中心，你的敏感范围内将产生一道力场，你可以凭自身意愿，随意改变力场中的重力分布。当你选择将重力改为超重时，所有处于该环境中承受超重状态的角色移动距离将降低为0，在表现上自上而下的重压将直接把人压制跪地，并使得具有飞行能力的角色立即下降一级飞行等级，视为处于A级困难地形；当你选择将重力改为失重时，所有在力场中的角色如失重般进行判定；这是一个S级环境来源的改变重力特性。你理所当然地不受自己力量的影响，这视为你具有S级环境来源免疫，而你也可以随时以一个自由动作关闭或重新开启重力场。<br> 【坠入地狱之门】：当其内心充斥的厌恶难以脱离灵与肉的束缚，其双眼便能看到窗外的自由——仅需纵身一跃，将罪恶感剥离；那是一把钥匙，为其开启地狱的门扉。现在所有的【敕罪】攻击额外附带有S级诅咒来源的即死效果：当以【敕罪】攻击时，目标以意志豁免对抗攻击出目，若其豁免失败，将直接丧失抵抗心理，其内心将被无尽的无力感充斥，就像选择了在高楼一跃而下般向前迈步，下一刻其立即反重力坠落至天穹之上，坠入凭空出现的地狱之门，成那门后饥肠辘辘的恶魔们的餐点消失。<br> 此时，若死者具有任意复活等级，其尸体最终会粉身碎骨地坠落回原位，通常而言，会是一堆残肢与内脏。<br> ）</p><p>下属强化技能树<br> 该下属技能树必须要购买对应等级的改造后才能开放购买权。</p><p>D级<br> 该等级每个能力价格皆为D＋500，正常获取自由属性点</p><p>【解放欲】：该技能在购买时需额外支付3XP，在购买了【解放欲】后，每购买一个【解放欲】之外的下落恶魔D级下属技艺，都会为你的【敕罪】攻击检定额外提供【破甲5】，最多获益3次。</p><p>【苛责】：购买之后，你每经历一场影片，都可以使【敕罪】进行的施法攻击检定额外附带有1点不可豁免的诅咒来源的【自责感】异常点数，最多以此成长3场影片。这是一种类疲乏的精神异常点数，严重状态为【无力感】，视为一种竭力状态；自责感点数可以正常与其它疲乏点数叠加。</p><p>【无端指控】：现在，你进行的【敕罪】攻击总是额外带有【贯穿】特性，这些攻击不止贯穿他人的外在，更能穿透他人的内心。以【敕罪】进行的法术攻击获得传奇风度*1点破甲，在计算破防效果后若是破甲仍有剩余，则等额转变为攻击上的亵渎加值，至多转变等于传奇风度*1的破甲。</p><p>【帮厨的基本素养】：你需要适应源自地狱的力量，掌控自身的非人本质，而这需要时间。购买该技能时不会立即获得任何的特性，但恶魔的种子早已在你的心底埋下，这意味着你需要在购买该资源后再经历一场影片，之后你将获得诅咒来源的基于视力的黑暗视觉，并且无需进食、无需休息、无需呼吸；你可以在光滑的固体平面与液体水面以基础移速自由行走，这些都是掌握了下落恶魔的非人本质与基本都重力掌握后获得的益处。<br> 最后，你以【敕罪】进行的施法攻击若不具有【法破】特性则使其带有【法破】。</p><p>C级<br> 该等级的每个能力价格皆为C＋1000，正常获取自由属性点。</p><p>【创伤性内斥】：现在，你可以在战斗中以一个迅捷动作使引力操纵的力量蕴含在下一次【敕罪】攻击中，若如此做，本回合无法再转化其他迅捷动作，这次攻击附带有1点不可豁免的流血异常点数，并使这次攻击的加骰提升一级（至多8加骰），针对这次攻击，你可以在攻击前选择将至多6点【破魔】转变为【破甲】。<br> 【崩溃漩涡】：现在，你在战斗中可以在投掷命中前以自由动作使这次【敕罪】检定法术攻击不造成伤害，而是转变为造成等量沮丧异常点数，意志豁免；无论如何，购买了【崩溃漩涡】后你的攻击总是带有1点不可豁免的沮丧点数。</p><p>B级<br> 该等级的每个能力价格皆为B+2000，正常获取自由属性点。</p><p>【吞噬罪孽】：被你以【敕罪】攻击杀死的单位无法以S级及以下的复活能力重生，这是一个诅咒来源的S级免疫复活能力。<br> 在购买该技能后经历一场战胜过同等级或以上敌人的影片，那之后，获得在意志豁免上的4dp亵渎加值，并使得【敕罪】施法攻击时从此额外附带有2点不可豁免的流血点数，若要判断来源，则视为诅咒来源。</p><p>本源联动下属能力<br> 该系列下属能力需要具有对应的本源才能应用效果，每个都是D+500</p><p>【赠予解脱】：现在，当你处于恶魔形态时，你造成的坠落伤害若在豁免后尾数不足6，则补齐至6，现在，你造成的坠落伤害最多还可以额外多造成6点，这会影响你的坠落伤害上限。</p><p>【描画罪恶】：现在，当敌人因击飞而下落时，【黑暗艺术】也会正常生效，坠落时改为每坠落10米便生效1点流血点数。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',28)])])}const f=e(s,[["render",d]]);export{D as __pageData,f as default};
